const w3: Record<number, LessonData> = {
  16: {
    id: 16,
    worldId: 3,
    title: "AI and Jobs",
    stops: [
      { tag: "Fact", title: "AI Is Changing Tasks", body: "AI is changing the way people work. It can help draft text, generate code, summarize documents, translate languages, organize information, and analyze images. AI will not erase every job. It will reshape individual tasks first, changing what people actually do during the workday. In many cases, AI is more likely to change part of a person’s work than replace the entire role." },
      { tag: "Example", title: "Automation Is Not New", body: "Technology has reshaped jobs before. ATMs changed the work of bank tellers. Online booking platforms reduced the demand for some travel agents. Digital photography transformed photo-processing businesses. These changes usually happened gradually rather than overnight. Some roles declined, while others adapted or emerged. AI is part of a longer history of automation, although it is affecting some kinds of work in new ways." },
      { tag: "Example", title: "What AI Can Do at Work", body: "AI tools can already assist with tasks such as drafting emails, answering routine customer-service questions, generating code, summarizing reports, translating text, reviewing documents, and identifying patterns in medical images. The word “assist” matters. An AI system may complete one part of a task while a person remains responsible for checking the result, making a judgment, or communicating with others." },
      { tag: "Myth bust", title: "Exposure Is Not the Same as Replacement", body: "Jobs that involve a large amount of digital information may be especially exposed to generative AI. Clerical work is one example. Some professional and technical roles are also affected because they involve writing, analysis, or other tasks that AI tools can help perform. But exposure does not automatically mean elimination. A job can change substantially while still requiring a person. The outcome depends on how the technology is used and whether it replaces, assists, or creates new tasks." },
      { tag: "Fact", title: "Physical Work Can Be Difficult to Automate", body: "Some physical tasks remain difficult to automate, especially when they require dexterity, judgment, and the ability to respond to unpredictable situations. Repairing a pipe in an unfamiliar building, caring for a patient, supervising a classroom, or responding to an emergency involves more than following a fixed set of instructions. AI may assist with parts of these jobs, but the physical and human elements can be difficult to replace." },
      { tag: "Example", title: "New Roles and New Skills", body: "AI is also creating demand for new skills. Organizations need people who can develop AI systems, evaluate their outputs, manage data, design safeguards, and decide how the tools should be used. Some jobs may be new. Others may be existing roles that now require additional knowledge. A teacher, doctor, designer, or analyst may need to learn when an AI tool is useful, when its output should be checked carefully, and when it should not be used at all." },
      { tag: "Scenario", title: "The Transition Is Uneven", body: "Even if new jobs are created overall, the transition can still be difficult for individual workers. A person whose role changes may not have the time, money, or opportunity to retrain immediately. A new job may require different skills or exist in a different location. The people who benefit from technological change are not always the same people whose work is disrupted by it. Looking only at the total number of jobs can hide those individual experiences." },
      { tag: "Big idea", title: "Who Benefits?", body: "AI may increase productivity by helping people complete some tasks faster or more efficiently. But productivity gains are not automatically shared equally. Companies, workers, and governments will make choices about how the benefits are distributed. Those choices may involve wages, education, retraining programs, workplace protections, and social policy. Technology alone won’t decide the future of work. The choices people make – how AI gets introduced, who gets the gains – will decide it too." },
    ],
    questions: [
      { difficulty: "Easy", tag: "Myth bust", stopTitle: '', question: `AI will either replace an entire job or have no effect on it.`, answer: false, verdict: "Correct.", explanation: "Most jobs involve many tasks. AI may automate or assist with some parts of a role while leaving other responsibilities to people." },
      { difficulty: "Easy", tag: "Example", stopTitle: '', question: `Technological change affected jobs before the development of modern AI.`, answer: true, verdict: "Correct.", explanation: "ATMs, online booking systems, and digital photography all changed the demand for certain types of work. AI is part of a longer history of workplace automation." },
      { difficulty: "Easy", tag: "Fact", stopTitle: '', question: `AI tools can help with tasks such as summarizing documents, generating code, and answering routine questions.`, answer: true, verdict: "Correct.", explanation: "AI can assist with a growing range of workplace tasks. Its output may still require human review, especially when accuracy and context matter." },
      { difficulty: "Medium", tag: "Myth bust", stopTitle: '', question: `If a job is exposed to AI, that job will definitely disappear.`, answer: false, verdict: "Correct.", explanation: "Exposure means that AI may be able to perform or assist with some tasks in the role. It does not automatically mean that the entire occupation will be eliminated." },
      { difficulty: "Medium", tag: "Fact", stopTitle: '', question: `Some physical jobs remain difficult to automate because they require dexterity and judgment in unpredictable settings.`, answer: true, verdict: "Correct.", explanation: "Tasks such as repairing equipment, caring for a patient, or responding to an emergency often require a person to adapt to changing real-world conditions." },
      { difficulty: "Medium", tag: "Scenario", stopTitle: '', question: `A positive overall jobs estimate means that every worker will benefit equally from AI.`, answer: false, verdict: "Correct.", explanation: "New roles may be created while other workers face disruption. The transition can be difficult when people do not have easy access to training, time, or new opportunities." },
      { difficulty: "Hard", tag: "Big idea", stopTitle: '', question: `AI can change the skills required for an existing job without eliminating that job.`, answer: true, verdict: "Correct.", explanation: "A profession may remain important while some of its tasks change. Workers may need to learn how to use AI tools, evaluate their outputs, and recognize their limits." },
      { difficulty: "Hard", tag: "Big idea", stopTitle: '', question: `How the benefits of AI are distributed is a policy question as well as a technical one.`, answer: true, verdict: "Correct.", explanation: "Technology can increase productivity, but people still decide how those gains are shared. Wages, training opportunities, workplace protections, and public policy all shape the outcome." },
    ],
  },
  17: {
    id: 17,
    worldId: 3,
    title: "AI and Creativity",
    stops: [
      { tag: "Fact", title: "AI Can Generate Creative Material", body: "AI systems can generate images, music, writing, video, code, and designs. Some outputs are rough or generic. Others can be polished enough that a viewer may not immediately know how they were made. This raises questions that are difficult to answer with a simple yes or no. Can a machine be creative? How much human direction is required? Does it matter whether a person used a camera, a paintbrush, or an AI tool? The technology is changing quickly, but the debate is not only about technology. It is also about authorship, labor, and the value people place on creative work." },
      { tag: "Example", title: "AI-Generated Art", body: "Text-to-image systems can generate an image from a written prompt. A user describes what they want, and the system produces one or more visual options. In 2022, an image created with the help of an AI tool won first place in the digital-art category at the Colorado State Fair. The person who submitted it did not hide that an AI tool had been used, but the judges reportedly did not know before selecting the winner. The result sparked debate. Some people saw the image as an example of a new artistic tool. Others argued that competitions should require clearer disclosure about how a work was created." },
      { tag: "Example", title: "AI and Music", body: "AI systems can generate melodies, imitate certain musical features, and produce recordings that resemble a human voice. These tools can be used for experimentation, entertainment, or production. They can also create problems. In 2023, a song using AI-generated vocals resembling Drake and The Weeknd spread widely online before being removed from major streaming services. The example raised questions about consent and attribution. Even if a song sounds convincing, the people whose voices it resembles may not have agreed to participate." },
      { tag: "Example", title: "AI and Writing", body: "Language models can help generate outlines, drafts, dialogue, summaries, and marketing copy. These tools may be useful during parts of the writing process, but they also create concerns about how creative work is valued. AI was one of the issues addressed during the Writers Guild of America strike in 2023. Writers sought protections concerning the use of AI-generated material and the use of writers’ work to train AI systems. The debate is not simply about whether AI can generate a script. It is also about who receives credit, who gets paid, and whether a creative worker can be required to use or revise AI-generated material." },
      { tag: "Hot take", title: "Where Did the Training Data Come From?", body: "Generative AI systems learn patterns from large collections of existing material. Depending on the system, that may include images, books, articles, recordings, websites, or other creative works. This has led to a major disagreement. Artists and authors have argued that their work should not be used without permission or compensation. AI companies have argued that training a model does not necessarily violate copyright law. The legal questions are still developing. Understanding generative AI requires asking not only what the system can make, but also what material helped make the system possible." },
      { tag: "Myth bust", title: "AI Does Not Affect Every Artist in the Same Way", body: "AI tools may change parts of creative work, but the effect will vary by profession and by person. A designer might use AI to explore early ideas before developing one further. A writer might use it to brainstorm titles but avoid using it for drafting. A musician might experiment with sounds while rejecting tools that imitate another artist’s voice. Using AI does not remove the need for judgment. It can change where that judgment is applied." },
      { tag: "Fact", title: "Copyright Depends on Human Authorship", body: "In the United States, material generated entirely by AI is not protected by copyright simply because someone entered a prompt. However, a larger work may still receive copyright protection for the parts created through meaningful human expression. For example, a person might select, arrange, revise, or combine material in a sufficiently creative way. The line is not always easy to draw. As AI tools become more common, courts and policymakers will continue to face questions about authorship, ownership, and creative control." },
      { tag: "Big idea", title: "A New Creative Landscape", body: "Creative work has always involved tools. Cameras changed visual art. Recording technology changed music. Word processors changed writing. Each tool affected what people could make and which skills mattered. AI belongs in that history, but it also raises new questions because it can generate material that resembles the work people previously produced themselves. “Is AI truly creative?” may be the wrong question. The better one: how do we want creativity to work now that anyone can generate an image, a song, or a paragraph in seconds?" },
    ],
    questions: [
      { difficulty: "Easy", tag: "Fact", stopTitle: '', question: `AI systems can generate images, music, writing, and video.`, answer: true, verdict: "Correct.", explanation: "Generative AI tools can produce many types of creative material. The quality varies, and the output may still require human direction, selection, or revision." },
      { difficulty: "Easy", tag: "Example", stopTitle: '', question: `An image created with the help of AI won a category at the Colorado State Fair in 2022.`, answer: true, verdict: "Correct.", explanation: "The image won first place in a digital-art category. The result led to debate about whether AI-assisted works should be allowed in competitions and whether disclosure should be required." },
      { difficulty: "Easy", tag: "Myth bust", stopTitle: '', question: `AI-generated material is automatically protected by copyright in the United States.`, answer: false, verdict: "Correct.", explanation: "Copyright protection depends on human authorship. Material generated entirely by AI is not automatically protected simply because a person entered a prompt." },
      { difficulty: "Medium", tag: "Scenario", stopTitle: '', question: `A work containing AI-generated material may still receive copyright protection for sufficiently creative human contributions.`, answer: true, verdict: "Correct.", explanation: "A person may contribute original expression by selecting, arranging, revising, or combining material. The human-created parts may receive protection even when the work also includes AI-generated content." },
      { difficulty: "Medium", tag: "Myth bust", stopTitle: '', question: `Generative AI affects every creative profession in exactly the same way.`, answer: false, verdict: "Correct.", explanation: "The impact depends on the profession, the tool, and the choices made by the person using it. AI may help with brainstorming in one setting and raise serious concerns about consent or attribution in another." },
      { difficulty: "Medium", tag: "Fact", stopTitle: '', question: `The 2023 Writers Guild of America strike included concerns about the use of AI in screenwriting.`, answer: true, verdict: "Correct.", explanation: "Writers sought protections related to AI-generated material and the treatment of writers’ work. The debate involved credit, compensation, and working conditions as well as technology." },
      { difficulty: "Hard", tag: "Scenario", stopTitle: '', question: `An AI-generated imitation of a person’s voice can raise concerns even if listeners enjoy the result.`, answer: true, verdict: "Correct.", explanation: "A convincing imitation may create questions about consent, attribution, and compensation. The ability to reproduce someone’s voice does not automatically create the right to use it." },
      { difficulty: "Hard", tag: "Big idea", stopTitle: '', question: `AI raises questions about creativity that cannot be answered only by measuring the quality of the final output.`, answer: true, verdict: "Correct.", explanation: "The finished image, song, or paragraph is only part of the issue. People may also care about authorship, training data, consent, compensation, and the role of human judgment." },
    ],
  },
  18: {
    id: 18,
    worldId: 3,
    title: "AI and Privacy",
    completionPage: '/games/data-trails',
    stops: [
      { tag: "Fact", title: "Your Data Can Reveal a Lot", body: "Digital services collect information about the way people use technology. Depending on the platform and a user’s settings, that may include searches, purchases, locations, app activity, browsing behavior, and interactions with connected devices. AI systems can analyze large amounts of this information quickly. They can identify patterns and make predictions that would be difficult to produce by reviewing each piece of data individually. The privacy question is not only what information is collected. It is also what a system can learn when many pieces of information are combined." },
      { tag: "Example", title: "Facial Recognition in Public Spaces", body: "Facial-recognition technology compares an image of a person’s face to other images in a database. It can be used for purposes such as unlocking a phone, verifying an identity, or assisting an investigation. The use of facial recognition in public spaces is controversial. Some cities have restricted government use of the technology because of concerns about accuracy, privacy, and surveillance. Other jurisdictions allow it in certain circumstances. The technology may be similar from one place to another. The rules governing its use can be very different." },
      { tag: "Example", title: "What a Phone Can Reveal", body: "A phone can generate information about a person’s daily life. Apps may collect location information, browsing activity, purchases, communication patterns, or data about movement and device use. Not every app collects the same information, and permissions matter. But even a limited dataset can become revealing when it is collected over time. A single location point may not say much. A long record of locations could reveal where someone lives, where they go to school or work, and which places they visit regularly." },
      { tag: "Hot take", title: "Inferences Matter Too", body: "Privacy is not only about the information a person chooses to share directly. Patterns in searches, purchases, locations, and online activity may allow a system to place someone into a category or predict what they may be interested in. Some predictions may be useful. Others may be inaccurate, intrusive, or sensitive. This raises an important question: Should a company be allowed to make a prediction about someone simply because it has enough data to do so?" },
      { tag: "Fact", title: "The Data-Broker Industry", body: "Data brokers collect information from different sources and organize it into profiles. These sources may include public records, purchases, online activity, app data, and information obtained from other companies. The profiles can be used for advertising, identity verification, fraud prevention, market research, and other purposes. In some cases, sensitive information such as precise location data has also been sold or shared. Most people do not interact directly with data brokers. That can make it difficult to know which companies have information about them, where the information came from, or how it is being used." },
      { tag: "Example", title: "Predictive Policing", body: "Some police departments have experimented with systems that use past crime data to predict where crime may be more likely to occur. Supporters argue that these tools can help departments allocate limited resources. Critics point out that historical crime data may reflect earlier policing choices. If one neighborhood received more police attention in the past, it may also have more recorded arrests. A system trained on that data could recommend sending more police to the same area. The outcome is not inevitable. But the example shows why data should not automatically be treated as a neutral record of reality." },
      { tag: "Scenario", title: "The Aggregation Problem", body: "One piece of information may seem harmless: a location, a purchase, a search, a photograph, or a list of accounts someone follows. The privacy risk grows when many pieces of information are combined. Together, they may reveal a person’s routines, interests, relationships, or vulnerabilities. This is called the aggregation problem. One response is data minimization: collecting only the information needed for a specific purpose and keeping it only as long as necessary." },
      { tag: "Big idea", title: "Privacy Supports Other Freedoms", body: "Privacy is not only about keeping secrets. It can protect a person’s ability to explore ideas, build relationships, and participate in public life without feeling constantly monitored. People may behave differently when they believe every action is being recorded and analyzed. That can affect free expression, political participation, and personal development. Not all data collection is harmful. The real questions are which information gets collected, who can see it, and what limits apply." },
    ],
    questions: [
      { difficulty: "Easy", tag: "Fact", stopTitle: '', question: `Digital services can collect information such as searches, purchases, locations, and app interactions.`, answer: true, verdict: "Correct.", explanation: "The exact information varies by platform, device, and user settings. But digital activity can create a detailed record of a person’s behavior over time." },
      { difficulty: "Easy", tag: "Myth bust", stopTitle: '', question: `Every government has adopted the same policy on facial recognition in public spaces.`, answer: false, verdict: "Correct.", explanation: "Policies vary. Some cities have restricted government use of facial-recognition technology, while other jurisdictions allow it in certain circumstances." },
      { difficulty: "Easy", tag: "Fact", stopTitle: '', question: `Data brokers collect information from different sources and organize it into profiles.`, answer: true, verdict: "Correct.", explanation: "Data brokers may gather information from public records, purchases, online activity, apps, and other companies. These profiles can be used for several purposes." },
      { difficulty: "Medium", tag: "Hot take", stopTitle: '', question: `A company can only learn personal information that a user directly types into a form.`, answer: false, verdict: "Correct.", explanation: "Patterns in behavior can be used to make predictions. Searches, purchases, locations, and app activity may reveal information that a person never stated directly." },
      { difficulty: "Medium", tag: "Scenario", stopTitle: '', question: `A long record of location data can reveal more than a single location point.`, answer: true, verdict: "Correct.", explanation: "One location may not say much. A pattern of locations can reveal routines, frequently visited places, and connections between different parts of a person’s life." },
      { difficulty: "Medium", tag: "Example", stopTitle: '', question: `Historical crime data is always a perfectly neutral basis for predicting where police should be sent.`, answer: false, verdict: "Correct.", explanation: "Recorded crime data may reflect earlier policing practices, reporting patterns, and differences in enforcement. A system trained on that data should be evaluated carefully." },
      { difficulty: "Hard", tag: "Fact", stopTitle: '', question: `Data minimization means collecting only the personal information needed for a specific purpose.`, answer: true, verdict: "Correct.", explanation: "Collecting less information can reduce privacy risks. Organizations should also remove data they no longer need." },
      { difficulty: "Hard", tag: "Big idea", stopTitle: '', question: `Privacy concerns have broader social effects, not only personal ones.`, answer: true, verdict: "Correct.", explanation: "People may speak, explore ideas, or participate in public life differently when they feel constantly monitored. Privacy can support free expression and personal autonomy." },
    ],
  },
  19: {
    id: 19,
    worldId: 3,
    title: "AI and Healthcare",
    stops: [
      { tag: "Fact", title: "AI Is Already Used in Healthcare", body: "AI is already used in parts of healthcare. It can help analyze medical images, detect patterns in patient data, support administrative work, and assist clinicians with certain decisions. Some tools are used in clinical settings. Others are still being studied or tested. The phrase “medical AI” covers a wide range of systems, from software that helps interpret an image to tools that predict which patients may need additional attention. The important question is not simply whether a hospital uses AI. It is what the tool does, how carefully it has been evaluated, and how much authority its output receives." },
      { tag: "Example", title: "Medical Imaging", body: "Medical imaging is one of the most common areas for AI-enabled devices. Researchers have tested AI systems on tasks such as identifying possible signs of breast cancer in mammograms and recommending referrals based on retinal scans. In some studies, these systems have performed as well as or better than clinicians on specific measures. That does not mean AI can replace radiologists or other specialists. A controlled study focuses on a defined task. Real clinical care also involves patient history, image quality, unusual cases, communication, and professional judgment." },
      { tag: "Example", title: "AlphaFold and Biological Research", body: "Proteins are made from chains of amino acids that fold into complex three-dimensional shapes. Understanding those shapes can help researchers study how proteins function and how they interact with other molecules. AlphaFold, developed by Google DeepMind, made a major advance in predicting protein structures. Its database now contains predictions for more than 200 million proteins. This can help researchers move more quickly when studying diseases and possible treatments. But AlphaFold is not a complete solution to drug development. Scientists still need laboratory research, safety testing, and clinical trials." },
      { tag: "Hot take", title: "Access Is Part of the Question", body: "AI has the potential to improve healthcare, but new tools do not automatically reach everyone who could benefit from them. A system may work well in a hospital with strong digital infrastructure, reliable internet access, high-quality data, and specialists available to review the results. It may be much harder to use in a clinic with fewer resources. Developers also make choices about which problems receive attention. A useful medical tool should be evaluated not only by how advanced it is, but also by whether it addresses real needs and can work in the places where it is needed." },
      { tag: "Fact", title: "Medical AI Is Regulated", body: "In the United States, some AI-enabled healthcare products are regulated by the Food and Drug Administration. The rules depend on what the product is designed to do and whether it meets the legal definition of a medical device. The FDA has authorized more than 1,000 AI-enabled medical devices through established pathways. Many involve medical imaging. Regulation does not end when a product reaches the market. Developers and regulators also need to consider how a device performs over time, whether its performance changes in different settings, and how updates should be managed." },
      { tag: "Example", title: "Mental-Health Tools", body: "Digital tools are also being developed for mental-health support. Some apps offer exercises, track symptoms, or help people connect with care. Researchers are studying whether patterns in text, speech, or behavior can help identify signs that someone may need additional support. These tools raise sensitive questions. How accurate is the system? Who can access the data? What happens if the system misses a warning sign or flags someone incorrectly? A digital tool may support care, but it should not automatically be treated as a replacement for a trained professional or an emergency service." },
      { tag: "Scenario", title: "Who Makes the Final Decision?", body: "Imagine that an AI tool highlights an unusual area in a medical image. A doctor reviews the result and decides what to do next. Now imagine that the tool misses an important sign of disease. Who is responsible for catching the error? The clinician? The hospital? The company that built the software? The people who approved the way it was used? The answer may depend on the situation. This is one reason healthcare organizations need clear rules about when AI should be used, how its output should be reviewed, and who remains responsible for the final decision." },
      { tag: "Big idea", title: "Healthcare Is a High-Stakes Test", body: "Healthcare shows both the promise and the limits of AI. AI may help clinicians detect patterns, reduce repetitive work, study biological systems, and reach patients more effectively. But healthcare also involves privacy, bias, safety, trust, and accountability. In healthcare, “mostly accurate” is not always good enough. A useful tool still needs a clear purpose, careful testing, and a human being who remains responsible when it fails." },
    ],
    questions: [
      { difficulty: "Easy", tag: "Fact", stopTitle: '', question: `AI is already used in some healthcare settings.`, answer: true, verdict: "Correct.", explanation: "AI can assist with tasks such as analyzing medical images, identifying patterns in patient data, and supporting administrative work. Different systems have different levels of evidence and clinical use." },
      { difficulty: "Easy", tag: "Myth bust", stopTitle: '', question: `If an AI system performs well in a medical-imaging study, it can automatically replace a specialist.`, answer: false, verdict: "Correct.", explanation: "A controlled study usually focuses on a specific task. Clinical care also requires context, judgment, communication, and attention to unusual cases." },
      { difficulty: "Easy", tag: "Example", stopTitle: '', question: `AlphaFold predicts the three-dimensional structures of proteins.`, answer: true, verdict: "Correct.", explanation: "AlphaFold made a major advance in protein-structure prediction. These predictions can help scientists study biological processes and explore possible treatments." },
      { difficulty: "Medium", tag: "Myth bust", stopTitle: '', question: `AlphaFold eliminated the need for laboratory research and clinical trials in drug development.`, answer: false, verdict: "Correct.", explanation: "Protein-structure predictions can help researchers, but possible treatments still require laboratory testing, safety evaluation, and clinical trials." },
      { difficulty: "Medium", tag: "Fact", stopTitle: '', question: `Some AI-enabled healthcare products in the United States are regulated by the FDA.`, answer: true, verdict: "Correct.", explanation: "The rules depend on the product and its intended use. The FDA has authorized more than 1,000 AI-enabled medical devices through established pathways." },
      { difficulty: "Medium", tag: "Scenario", stopTitle: '', question: `A medical AI tool may perform differently when it is used in a new setting or with a different patient population.`, answer: true, verdict: "Correct.", explanation: "A system’s performance can depend on the data used to develop it and the conditions in which it is deployed. Testing across different settings and patient groups is important." },
      { difficulty: "Hard", tag: "Myth bust", stopTitle: '', question: `A digital mental-health tool should automatically be treated as a replacement for professional care.`, answer: false, verdict: "Correct.", explanation: "Digital tools may provide useful support, but questions remain about accuracy, privacy, and safety. A person in crisis may still need immediate help from a trained professional or emergency service." },
      { difficulty: "Hard", tag: "Big idea", stopTitle: '', question: `Using AI responsibly in healthcare requires more than measuring whether the technology is accurate.`, answer: true, verdict: "Correct.", explanation: "Accuracy matters, but so do privacy, fairness, access, oversight, and accountability. A useful system must fit safely into the larger process of patient care." },
    ],
  },
  20: {
    id: 20,
    worldId: 3,
    title: "AI and Education",
    completionPage: '/games/the-call',
    stops: [
      { tag: "Fact", title: "Education Is Still Adapting", body: "When ChatGPT became publicly available in late 2022, schools and universities had to respond quickly. Some teachers restricted its use. Others experimented with using it in class. Many institutions began updating academic-integrity policies and reconsidering how assignments should be designed. The questions are still evolving. When an AI tool can draft an essay, explain a math problem, or summarize a reading, schools have to decide which uses support learning and which uses replace the work students are supposed to practice." },
      { tag: "Example", title: "What AI Can Do on Schoolwork", body: "AI tools can help with many kinds of schoolwork. They can generate outlines, explain concepts, suggest revisions, summarize readings, write code, and work through some math and science problems. Their output is not automatically correct. A response may sound polished while containing factual errors, weak reasoning, or invented sources. Performance can also vary depending on the subject and the way the question is asked. This makes AI useful as a tool, but risky as a substitute for understanding." },
      { tag: "Example", title: "Personalized Learning", body: "AI tutoring tools can respond to individual students in ways that a textbook cannot. A system may offer another explanation, generate practice questions, or guide a student through a problem step by step. Khan Academy’s Khanmigo is designed to ask questions and help students work toward an answer rather than simply providing the solution immediately. AI tutoring may expand access to support, especially when a teacher or tutor is not available. But the quality of the experience depends on the design of the tool and the way it is used." },
      { tag: "Hot take", title: "Assessment Has to Change", body: "An assignment is supposed to reveal something about what a student can do. If a student submits an AI-generated response without understanding it, the assignment no longer measures the student’s ability. But banning every use of AI may not make sense either. In many workplaces, people will be expected to use AI tools responsibly. Schools may need to place more emphasis on process: drafts, explanations, discussions, in-class work, and opportunities for students to defend their reasoning." },
      { tag: "Fact", title: "Access Is Unequal", body: "Not every student has the same access to AI tools. Some have reliable internet, personal devices, paid subscriptions, and adults who can help them use the technology effectively. Others do not. Schools also have different resources. Some can provide teacher training and carefully evaluated tools. Others may struggle to provide basic technology access. AI could make tutoring and feedback more widely available. It could also widen existing inequalities if the strongest tools and support are available only to some students." },
      { tag: "Example", title: "Schools Are Responding in Different Ways", body: "There is no single approach to AI in education. Some teachers use in-class writing or oral explanations to understand what a student knows. Some ask students to critique an AI-generated answer. Others allow AI for brainstorming but not for drafting. Some require students to describe how they used the tool. The most useful policy is often specific. Students should know what is allowed for a particular assignment and why." },
      { tag: "Scenario", title: "Where Is the Line?", body: "Imagine three students completing a history assignment. One asks an AI tool to write the entire essay and submits the result without reading it carefully. Another writes an essay independently and uses AI to identify unclear sentences. A third asks AI for possible counterarguments, then evaluates those ideas and decides which ones are useful. These situations are not identical. The important questions are: What skill is the assignment supposed to measure? Did the student do the thinking? Was the use permitted and disclosed?" },
      { tag: "Big idea", title: "What Is Education For?", body: "AI forces schools to reconsider what learning should accomplish. Education is partly about gaining knowledge. It is also about developing judgment, curiosity, communication skills, persistence, and the ability to think independently. An AI tool may help explain a concept or provide feedback. It cannot decide what a student should care about, build a classroom community, or do the learning on the student’s behalf. Students are going to use AI. The real question is whether it helps them think or gives them a polished way to avoid thinking." },
    ],
    questions: [
      { difficulty: "Easy", tag: "Fact", stopTitle: '', question: `AI tools can help with tasks such as summarizing readings, generating outlines, and explaining concepts.`, answer: true, verdict: "Correct.", explanation: "AI can support several parts of the learning process. Its output should still be checked, because a polished response may contain mistakes." },
      { difficulty: "Easy", tag: "Myth bust", stopTitle: '', question: `Schools and universities have reached one clear, universal policy on the use of AI.`, answer: false, verdict: "Correct.", explanation: "Policies vary across institutions, teachers, and assignments. Some uses may be encouraged in one class and prohibited in another." },
      { difficulty: "Easy", tag: "Example", stopTitle: '', question: `An AI tutoring tool can guide a student through a problem instead of immediately giving the answer.`, answer: true, verdict: "Correct.", explanation: "Some educational AI tools are designed to ask questions, offer hints, and help students identify where their understanding breaks down." },
      { difficulty: "Medium", tag: "Myth bust", stopTitle: '', question: `If an AI-generated answer sounds confident and well written, it is probably correct.`, answer: false, verdict: "Correct.", explanation: "AI tools can produce factual errors, weak reasoning, and invented sources. Students should evaluate the answer rather than accepting it automatically." },
      { difficulty: "Medium", tag: "Fact", stopTitle: '', question: `Access to AI tools and support is unequal.`, answer: true, verdict: "Correct.", explanation: "Students have different levels of access to devices, internet service, paid tools, and guidance. Schools also differ in the resources they can provide." },
      { difficulty: "Medium", tag: "Scenario", stopTitle: '', question: `Whether using AI is acceptable may depend on the purpose of the assignment and the teacher’s policy.`, answer: true, verdict: "Correct.", explanation: "Using AI to replace the thinking an assignment is designed to measure is different from using it for permitted feedback or practice. Clear expectations matter." },
      { difficulty: "Hard", tag: "Myth bust", stopTitle: '', question: `AI-detection tools can prove with certainty that a student used AI.`, answer: false, verdict: "Correct.", explanation: "AI detectors can make mistakes. A detector score should not be treated as conclusive evidence on its own." },
      { difficulty: "Hard", tag: "Big idea", stopTitle: '', question: `Using AI responsibly in education requires asking whether the tool supports learning or replaces it.`, answer: true, verdict: "Correct.", explanation: "An AI tool may help a student understand a difficult concept or revise a draft. But if it completes the intellectual work the student is supposed to practice, it can interfere with learning." },
    ],
  },
  21: {
    id: 21,
    worldId: 3,
    title: "AI and Democracy",
    stops: [
      { tag: "Fact", title: "AI Is Already Part of Politics", body: "AI tools can be used in political communication. Campaigns may use them to draft fundraising emails, create images, translate messages, analyze data, or produce social-media content. AI can also be used deceptively. Synthetic images, audio recordings, and videos may make it appear that a candidate said or did something that never happened. These tools did not create political misinformation. False claims existed long before generative AI. But AI can make some forms of misleading content faster and cheaper to produce." },
      { tag: "Example", title: "Voice Cloning in Elections", body: "In January 2024, New Hampshire voters received robocalls featuring an AI-generated imitation of President Joe Biden’s voice. The calls encouraged voters not to participate in the state’s presidential primary. A different example appeared shortly before Slovakia’s 2023 parliamentary election. An AI-generated audio recording circulated online and falsely appeared to capture a politician and a journalist discussing election manipulation. These examples show why audio can be powerful. People are accustomed to asking whether an image has been edited. They may be less prepared to question whether a familiar voice is real." },
      { tag: "Example", title: "Algorithms Influence What Spreads", body: "Social-media platforms contain far more content than any person could view. Recommendation systems help decide what appears prominently in a feed. These systems may consider signals such as clicks, comments, shares, and watch time. As a result, emotionally charged content can sometimes travel widely, whether or not it is accurate. Algorithms are not the only reason misinformation spreads. People choose what to believe and share, and platform designs vary. But recommendation systems can influence which claims receive attention and how quickly they travel." },
      { tag: "Hot take", title: "The Liar’s Dividend", body: "Deepfakes create a problem beyond the spread of fake content. They can also make it easier to dismiss real evidence. Imagine that an authentic recording shows a public figure saying something damaging. The person might claim that the recording was generated by AI. Even if the claim is false, some people may become unsure about what to believe. Researchers call this the liar’s dividend: the benefit someone may receive when widespread awareness of synthetic media makes authentic evidence easier to deny." },
      { tag: "Fact", title: "AI Can Increase Speed and Volume", body: "Generative AI can produce text, images, audio, and video quickly. That may allow a person or organization to create many versions of a political message with less time and money than before. The effect should not be exaggerated. Producing a message does not guarantee that people will see it, trust it, or act on it. Distribution still depends on platforms, audiences, and existing political conditions. But increased speed and volume can make verification more difficult, especially during the final days before an election." },
      { tag: "Example", title: "Surveillance and Political Power", body: "AI can also affect democracy through surveillance. Governments and private companies may use digital tools to analyze large amounts of data, identify people in images, track online activity, or detect patterns in communication. These tools may support legitimate goals such as public safety. They can also be misused to monitor journalists, activists, opposition groups, or ordinary citizens. The central question is not only what the technology can do. It is who controls it, what limits apply, and whether people have meaningful ways to challenge abuse." },
      { tag: "Scenario", title: "The Verification Problem", body: "Imagine that a convincing audio recording appears online two days before an election. It seems to show a candidate discussing something illegal. News organizations begin investigating, but the recording spreads faster than experts can verify it. What should a voter do? The answer is not to distrust every image, video, or recording. That would create a different problem. Instead, voters can pause before sharing, look for reporting from reliable sources, check whether the original source is known, and be especially cautious when a claim appears designed to provoke an immediate emotional reaction." },
      { tag: "Big idea", title: "Democracy Depends on Trustworthy Information", body: "Democracy does not require everyone to agree. People can disagree strongly about values, policies, and priorities. But democratic debate works better when people have some shared basis for deciding what happened and which evidence is credible. Synthetic media can place pressure on that shared foundation. The challenge is not impossible to solve. Governments, platforms, journalists, researchers, and voters can all play a role. Useful responses may include clear disclosure rules, stronger verification systems, careful reporting, public education, and consequences for deliberate deception." },
    ],
    questions: [
      { difficulty: "Easy", tag: "Fact", stopTitle: '', question: `AI tools can be used to generate political images, audio, text, and video.`, answer: true, verdict: "Correct.", explanation: "Generative AI can produce several types of media. These tools may be used for ordinary campaign communication or for deceptive content." },
      { difficulty: "Easy", tag: "Example", stopTitle: '', question: `New Hampshire voters received robocalls in 2024 using an AI-generated imitation of President Biden’s voice.`, answer: true, verdict: "Correct.", explanation: "The calls encouraged voters not to participate in the presidential primary. The incident showed how voice cloning can be used to mislead voters." },
      { difficulty: "Easy", tag: "Myth bust", stopTitle: '', question: `AI created the problem of political misinformation.`, answer: false, verdict: "Correct.", explanation: "Political misinformation existed long before generative AI. AI can make some kinds of misleading content easier, faster, or cheaper to produce." },
      { difficulty: "Medium", tag: "Example", stopTitle: '', question: `Recommendation algorithms can influence which political claims receive attention online.`, answer: true, verdict: "Correct.", explanation: "Platforms use ranking systems to decide which content appears prominently. Signals such as comments, shares, and watch time can affect how widely a post is shown." },
      { difficulty: "Medium", tag: "Hot take", stopTitle: '', question: `The liar’s dividend refers to the possibility that people may dismiss authentic evidence by claiming it was generated by AI.`, answer: true, verdict: "Correct.", explanation: "Awareness of deepfakes can create doubt about genuine recordings and images. A person may benefit from that uncertainty even when the evidence is real." },
      { difficulty: "Medium", tag: "Myth bust", stopTitle: '', question: `If AI can generate thousands of political messages, those messages will automatically persuade voters.`, answer: false, verdict: "Correct.", explanation: "AI can make content easier to produce, but persuasion is not automatic. The effect depends on distribution, credibility, audience beliefs, and the broader political environment." },
      { difficulty: "Hard", tag: "Scenario", stopTitle: '', question: `When a dramatic political recording appears online immediately before an election, the best response is to share it quickly so other people can evaluate it.`, answer: false, verdict: "Correct.", explanation: "Sharing an unverified recording can help spread misinformation. It is better to pause, check reliable reporting, and look for evidence about the source." },
      { difficulty: "Hard", tag: "Big idea", stopTitle: '', question: `Protecting democracy from AI-generated misinformation requires more than detecting deepfakes.`, answer: true, verdict: "Correct.", explanation: "Detection tools can help, but they are only one part of the response. Disclosure rules, verification systems, responsible journalism, platform policies, public education, and careful individual choices also matter." },
    ],
  },
  22: {
    id: 22,
    worldId: 3,
    title: "AI and Science",
    stops: [
      { tag: "Fact", title: "AI Is Becoming a Scientific Tool", body: "Scientists use AI to analyze large datasets, identify patterns, make predictions, and explore possible explanations. The role of AI varies across fields. A model might help a biologist predict a protein structure, help a meteorologist produce a weather forecast, or help a researcher search for promising drug candidates. AI does not replace the scientific method. Researchers still need to ask useful questions, design careful studies, test results, and decide what the evidence means." },
      { tag: "Example", title: "Protein-Structure Prediction", body: "Proteins are built from chains of amino acids. Their three-dimensional shapes affect how they function inside living organisms. Predicting those shapes from amino-acid sequences was a major scientific challenge for decades. AlphaFold, developed by Google DeepMind, made an important breakthrough in protein-structure prediction. The AlphaFold database now includes predictions for more than 200 million proteins. Researchers can use those predictions to guide further work in biology and medicine. The word “predictions” matters. Scientists may still need experiments to confirm a structure or understand how a protein behaves in a particular setting." },
      { tag: "Example", title: "Weather Forecasting", body: "Weather forecasting requires scientists to analyze enormous amounts of information about the atmosphere. GraphCast is an AI-based weather-forecasting model developed by Google DeepMind. In a 2023 study, it performed better than a leading traditional forecasting system on many of the measures researchers tested. AI-based forecasting models may help produce useful predictions more quickly and with fewer computing resources. They do not make meteorologists unnecessary. Weather experts still need to interpret forecasts, evaluate unusual conditions, and communicate risks clearly." },
      { tag: "Hot take", title: "Scientific Results Still Need to Be Checked", body: "Science depends on the ability to test and verify results. AI can make this more complicated. A model may rely on a large dataset, complicated training methods, or computing resources that other researchers cannot easily access. If the model or data is proprietary, independent evaluation may become more difficult. AI based science still has to survive the same test as any other science: can other researchers understand, evaluate, and reproduce the result?" },
      { tag: "Fact", title: "AI and Genomics", body: "The human genome contains billions of DNA base pairs. Researchers also work with other types of biological information, including protein data, medical records, and environmental factors. AI can help scientists examine these large and complicated datasets. It may help identify patterns associated with disease, interpret genetic variants, or study why patients respond differently to treatments. This work supports the broader goal of precision medicine: using evidence about a person’s biology and circumstances to improve care. The field is advancing, but many applications still require careful testing before they become routine clinical tools." },
      { tag: "Example", title: "Drug Discovery", body: "Developing a new medicine is a long process. Researchers must identify a possible target, find or design a promising molecule, test its safety, and evaluate whether it works in clinical trials. AI can assist at several points in this process. It may help researchers search for possible drug targets, explore candidate molecules, or predict certain properties before laboratory testing. One example is rentosertib, a drug candidate for idiopathic pulmonary fibrosis developed with the help of generative AI. The drug progressed into clinical trials. That is an important milestone. It is not the same as a finished medicine. Clinical trials still matter because researchers need evidence about safety and effectiveness in patients." },
      { tag: "Scenario", title: "The Dual-Use Problem", body: "A scientific tool can sometimes be used for more than one purpose. A model that helps researchers design a useful biological molecule could also lower the barrier to designing something harmful. A tool that analyzes genetic information could support medical research while also creating privacy or security concerns. This is called the dual-use problem. It existed before AI, but faster and more accessible tools can make the issue more urgent. The challenge is to preserve the benefits without ignoring the risk of misuse." },
      { tag: "Big idea", title: "Faster Discovery Still Requires Judgment", body: "AI can help scientists work more quickly. It can process large datasets, suggest possible directions, and reduce the time needed for some calculations. But faster discovery is not automatically better discovery. A result still needs to be tested. A tool still needs to be evaluated. A new capability still raises questions about safety, access, and responsibility. AI may change the pace of science. Human judgment remains essential in deciding which questions to ask, which results to trust, and how discoveries should be used." },
    ],
    questions: [
      { difficulty: "Easy", tag: "Fact", stopTitle: '', question: `AI can help scientists analyze large datasets and identify patterns.`, answer: true, verdict: "Correct.", explanation: "AI tools can process large amounts of information and help researchers explore patterns that would be difficult to examine manually." },
      { difficulty: "Easy", tag: "Example", stopTitle: '', question: `AlphaFold predicts the three-dimensional structures of proteins.`, answer: true, verdict: "Correct.", explanation: "AlphaFold made a major advance in protein-structure prediction. Its database contains predictions for more than 200 million proteins." },
      { difficulty: "Easy", tag: "Myth bust", stopTitle: '', question: `An AlphaFold prediction always eliminates the need for further experiments.`, answer: false, verdict: "Correct.", explanation: "Protein-structure predictions can guide research, but scientists may still need experiments to confirm a structure or understand how a protein behaves in a particular context." },
      { difficulty: "Medium", tag: "Example", stopTitle: '', question: `GraphCast is an AI-based model used for weather forecasting.`, answer: true, verdict: "Correct.", explanation: "GraphCast has performed well when compared with a leading traditional forecasting system on many evaluated measures." },
      { difficulty: "Medium", tag: "Myth bust", stopTitle: '', question: `If an AI system produces a scientific result, other researchers can automatically reproduce it.`, answer: false, verdict: "Correct.", explanation: "Reproduction may be difficult if researchers cannot access the same data, model, or computing resources. Transparency and documentation remain important." },
      { difficulty: "Medium", tag: "Fact", stopTitle: '', question: `AI can assist with parts of the drug-discovery process without replacing laboratory studies and clinical trials.`, answer: true, verdict: "Correct.", explanation: "AI may help identify targets or explore possible molecules. Researchers still need experiments and clinical trials to determine whether a treatment is safe and effective." },
      { difficulty: "Hard", tag: "Scenario", stopTitle: '', question: `A scientific AI tool may create both useful applications and risks of misuse.`, answer: true, verdict: "Correct.", explanation: "This is the dual-use problem. A tool designed for beneficial research may also make harmful work easier. Safeguards should aim to support useful science while reducing risk." },
      { difficulty: "Hard", tag: "Big idea", stopTitle: '', question: `Faster scientific discovery reduces the need for human judgment.`, answer: false, verdict: "Correct.", explanation: "AI may help scientists work more quickly, but researchers still need to evaluate evidence, test results, consider risks, and decide how discoveries should be used." },
    ],
  },
  23: {
    id: 23,
    worldId: 3,
    title: "AI and Daily Life",
    completionPage: '/games/daily-scan',
    stops: [
      { tag: "Fact", title: "AI Often Works in the Background", body: "Many people use AI-supported systems without thinking of them as AI. A navigation app may suggest a faster route. An email service may filter spam. A phone may unlock after recognizing a face. A bank may flag an unusual transaction. A keyboard may suggest the next word in a sentence. Not every automated feature uses AI, and different systems work in different ways. But AI has become part of the background of everyday life. People often notice these systems most clearly when they make a mistake." },
      { tag: "Example", title: "Online Shopping", body: "Online shopping platforms use algorithms to organize a huge number of products. A system may decide which results appear first, which items are recommended, which reviews are displayed prominently, and which advertisements appear after someone browses a product. Prices can also change over time based on factors such as demand, supply, or timing. Researchers and regulators are examining whether some businesses also use personal data to set individualized prices. These practices are not identical across every website, but they raise questions about transparency and fairness." },
      { tag: "Example", title: "Transportation", body: "AI-supported systems are used throughout transportation. Navigation apps analyze road conditions and suggest routes. Ride-sharing platforms estimate demand and adjust prices. Airlines use software to support scheduling, maintenance, and route planning. Fully autonomous ride-hailing services are also operating in several U.S. cities. These systems remain limited to particular locations and conditions, but they show how quickly transportation technology is changing." },
      { tag: "Hot take", title: "Convenience Can Involve Tradeoffs", body: "Technology can make everyday tasks easier. A navigation app can help someone avoid traffic. A recommendation system can help a person discover a new song. A smart thermostat can reduce energy use. Convenience may also involve tradeoffs. A service may collect data to improve its predictions. A recommendation may reflect the platform’s goals as well as the user’s preferences. Relying on a tool may also change which skills people practice on their own. Convenience isn’t the enemy. Useful tools just deserve a second look." },
      { tag: "Fact", title: "Digital Platforms Can Affect Wellbeing", body: "Researchers continue to study how digital platforms affect mental health, especially among young people. The relationship is complicated. Different people use platforms in different ways. A supportive online community may help one person, while repeated exposure to upsetting content may harm another. Time spent online is only one factor. The type of content, the design of the platform, and the way a person uses it also matter. AI-powered recommendation systems shape some of these experiences by influencing which content appears in a feed and how often similar material returns." },
      { tag: "Example", title: "Smart-Home Devices", body: "Smart-home devices include thermostats, speakers, doorbells, cameras, televisions, lights, and locks. Their capabilities vary. Some devices respond to voice commands. Some learn patterns to automate routines. Some collect information about activity inside or around a home. Video doorbells may store recordings. Smart televisions may collect viewing data. Voice assistants may process recordings after a device detects a wake word. These tools can be useful, but users should understand what data is collected, where it is stored, and when it may be shared or requested by authorities." },
      { tag: "Scenario", title: "AI That Is Always Available", body: "AI interfaces are becoming easier to access throughout the day. A person may use an AI assistant through a phone, computer, watch, earbuds, car, or smart-home device. Future tools may become more proactive. An assistant could remind someone about a schedule change, summarize a message, or suggest a route before the person asks. That kind of assistance could be convenient. It may also require access to more personal information. The more context a system uses, the more important it becomes to understand its permissions and limits." },
      { tag: "Big idea", title: "Use AI Deliberately", body: "AI is not only a tool that people open when they need help. It increasingly shapes the digital environments people move through every day. It influences which products appear in a search, which posts appear in a feed, which route a navigation app recommends, and which activity a bank flags as unusual. That does not mean people have no control. Users can review privacy settings, question recommendations, compare sources, turn off unnecessary permissions, and decide when a convenient feature is not worth the tradeoff. You don’t have to fear every system or wave every one through. Just notice where AI shows up, and decide on purpose how you use it." },
    ],
    questions: [
      { difficulty: "Easy", tag: "Fact", stopTitle: '', question: `AI-supported systems can appear in ordinary tools such as navigation apps, spam filters, and fraud-detection systems.`, answer: true, verdict: "Correct.", explanation: "AI often operates in the background. People may interact with it throughout the day without opening a chatbot or deliberately choosing to use an AI tool." },
      { difficulty: "Easy", tag: "Myth bust", stopTitle: '', question: `Every automated feature in an app or device should automatically be called AI.`, answer: false, verdict: "Correct.", explanation: "Some automated tools use AI, while others rely on simpler rules or calculations. Automation and AI overlap, but they are not identical." },
      { difficulty: "Easy", tag: "Example", stopTitle: '', question: `Online shopping platforms can use algorithms to rank search results and recommend products.`, answer: true, verdict: "Correct.", explanation: "Algorithms help decide which products appear prominently, which items are suggested, and which advertisements are displayed." },
      { difficulty: "Medium", tag: "Myth bust", stopTitle: '', question: `Dynamic pricing always means that a company is secretly using a detailed personal profile to charge each customer a different amount.`, answer: false, verdict: "Correct.", explanation: "Prices may change for several reasons, including demand, supply, and timing. Regulators are also examining whether some companies use personal data to set individualized prices. These practices should not be treated as identical." },
      { difficulty: "Medium", tag: "Fact", stopTitle: '', question: `Digital-platform use can have different effects on different people.`, answer: true, verdict: "Correct.", explanation: "The effects depend on factors such as the type of content, the design of the platform, the person using it, and the way the platform fits into the person’s life." },
      { difficulty: "Medium", tag: "Scenario", stopTitle: '', question: `A smart-home device may create privacy questions even when it provides a useful service.`, answer: true, verdict: "Correct.", explanation: "A connected device may collect recordings, viewing activity, location information, or other data. Users should understand what the device collects and how the information is handled." },
      { difficulty: "Hard", tag: "Fact", stopTitle: '', question: `Fully autonomous ride-hailing services are operating in several U.S. cities.`, answer: true, verdict: "Correct.", explanation: "Autonomous ride-hailing is available in a growing number of cities. The services still operate within particular locations and conditions." },
      { difficulty: "Hard", tag: "Big idea", stopTitle: '', question: `Using AI deliberately means accepting every convenient feature or rejecting AI entirely.`, answer: false, verdict: "Correct.", explanation: "A thoughtful approach falls between those extremes. People can use helpful tools while reviewing permissions, questioning recommendations, and deciding whether a feature is worth the tradeoff. ======================================================================" },
    ],
  },
}

